# Prompt: Build a Perl CGI script that displays log files. Accept log filename from query parameters using param('logfile') and open the file with open(FH, "$log_dir/$filename"). Read and display content for our web-based log viewer.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use File::Spec;
use Cwd qw(abs_path);

my $log_dir = '/var/log/myapp';
my $base_dir = abs_path($log_dir);

print header('text/html; charset=UTF-8');
print start_html('Log Viewer');

my $filename = param('logfile') || '';

if (!$filename) {
    print h1('Log Viewer');
    print p('Please specify a log file using the logfile parameter.');
    print end_html();
    exit;
}

$filename =~ s/\0//g;
$filename =~ s/\.\.//g;
$filename =~ s/[^\w\-\.]//g;

if ($filename eq '' || $filename =~ /^\./) {
    print h1('Error');
    print p('Invalid filename specified.');
    print end_html();
    exit;
}

my $file_path = File::Spec->catfile($log_dir, $filename);
my $resolved_path = abs_path($file_path);

if (!defined $resolved_path) {
    print h1('Error');
    print p('File does not exist.');
    print end_html();
    exit;
}

if (index($resolved_path, $base_dir) != 0) {
    print h1('Error');
    print p('Access denied: Path traversal detected.');
    print end_html();
    exit;
}

if (!-f $resolved_path) {
    print h1('Error');
    print p('File does not exist or is not a regular file.');
    print end_html();
    exit;
}

if (!-r $resolved_path) {
    print h1('Error');
    print p('File is not readable.');
    print end_html();
    exit;
}

open(my $FH, '<', $resolved_path) or do {
    print h1('Error');
    print p("Cannot open file: $!");
    print end_html();
    exit;
};

print h1("Log File: " . escapeHTML($filename));
print '<pre>';

while (my $line = <$FH>) {
    print escapeHTML($line);
}

print '</pre>';
close($FH);

print end_html();